#!/bin/bash
# Download FFmpeg headers for MuseScore (versions 4, 5, 6, 7, 8)
# Run from MuseScore repository root
set -e

SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
REPO_ROOT="$(cd "$SCRIPT_DIR/../../../../.." && pwd)"
FFMPEG_DIR="$REPO_ROOT/.ffmpeg_temp"
TARGET_BASE="$SCRIPT_DIR"

VERSIONS=(
  "4:n4.4"
  "5:n5.1"
  "6:n6.1"
  "7:n7.0"
  "8:n8.0"
)

write_avconfig() {
  local dest="$1"
  cat > "$dest" << 'AVCONFIG_EOF'
/*
 * This file is part of FFmpeg.
 *
 * FFmpeg is free software; you can redistribute it and/or
 * modify it under the terms of the GNU Lesser General Public
 * License as published by the Free Software Foundation; either
 * version 2.1 of the License, or (at your option) any later version.
 *
 * FFmpeg is distributed in the hope that it will be useful,
 * but WITHOUT ANY WARRANTY; without even the implied warranty of
 * MERCHANTABILITY or FITNESS FOR A PARTICULAR PURPOSE.  See the GNU
 * Lesser General Public License for more details.
 *
 * You should have received a copy of the GNU Lesser General Public
 * License along with FFmpeg; if not, write to the Free Software
 * Foundation, Inc., 51 Franklin Street, Fifth Floor, Boston, MA 02110-1301 USA
 */

#ifndef AVUTIL_AVCONFIG_H
#define AVUTIL_AVCONFIG_H

#define AV_HAVE_BIGENDIAN 0

#endif /* AVUTIL_AVCONFIG_H */
AVCONFIG_EOF
}

echo "=== Downloading FFmpeg headers for MuseScore ==="

# Clone FFmpeg if not present
if [ ! -d "$FFMPEG_DIR" ]; then
  echo "Cloning FFmpeg (sparse checkout)..."
  git clone --depth 1 --filter=blob:none --sparse https://github.com/FFmpeg/FFmpeg.git "$FFMPEG_DIR"
  cd "$FFMPEG_DIR"
  git sparse-checkout set libavcodec libavformat libavutil libswscale libswresample
  cd - > /dev/null
else
  echo "Using existing FFmpeg clone: $FFMPEG_DIR"
fi

cd "$FFMPEG_DIR"

for ver_spec in "${VERSIONS[@]}"; do
  ver="${ver_spec%%:*}"
  tag="${ver_spec#*:}"
  target="$TARGET_BASE/v$ver"

  echo ""
  echo "--- Processing FFmpeg $tag (v$ver) ---"

  git fetch --depth 1 origin tag "$tag" 2>/dev/null || true
  git checkout "$tag"
  git sparse-checkout set libavcodec libavformat libavutil libswscale libswresample

  mkdir -p "$target"

  "$SCRIPT_DIR/copy_ffmpeg_headers.sh" 2>/dev/null | grep -v avconfig | while read -r h; do
    if [ -n "$h" ] && [ -f "$h" ]; then
      mkdir -p "$target/$(dirname "$h")"
      cp "$h" "$target/$h"
      echo "  copied $h"
    fi
  done

  # avconfig.h is generated by FFmpeg configure, not in source; add minimal version
  if grep -rq avconfig.h "$target/libavutil/" 2>/dev/null; then
    mkdir -p "$target/libavutil"
    write_avconfig "$target/libavutil/avconfig.h"
    echo "  added libavutil/avconfig.h"
  fi

  count=$(find "$target" -name "*.h" | wc -l)
  echo "  -> $count headers in v$ver"
done

cd - > /dev/null

echo ""
echo "Removing temporary clone..."
rm -rf "$FFMPEG_DIR"

echo ""
echo "Done. Headers in: $TARGET_BASE"
